module	RefModule(CLK, CE, WRITE, I, O, BUSY);
	input			CLK, CE, WRITE;
	input		[15:0]	I;
	output	wire	[15:0]	O;
	output	wire	BUSY;
	reg	[15:0]	unused_rv;
	initial	unused_rv = 16'h0000;
	always @(posedge CLK)
		if ((CE)&&(WRITE))
			unused_rv <= I;
	assign	O = unused_rv;
	assign	BUSY = 1'b0;
endmodule
